'use client';

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, getUserById, getCurrentUserIdFromStorage, clearCurrentUserIdFromStorage } from '../utils/storage';

interface AuthContextType {
  user: User | null;
  login: (user: User) => void;
  logout: () => void;
  updateCurrentUser: (updates: Partial<User>) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const currentUserId = getCurrentUserIdFromStorage();
    if (currentUserId) {
      if (currentUserId === 'admin') {
        setUser({
          id: 'admin',
          name: 'System Administrator',
          email: 'admin@school.edu',
          password: 'ADMIN@2026',
          role: 'admin'
        });
      } else {
        const currentUser = getUserById(currentUserId);
        if (currentUser) {
          setUser(currentUser);
        }
      }
    }
  }, []);

  const login = (user: User) => {
    setUser(user);
  };

  const logout = () => {
    clearCurrentUserIdFromStorage();
    setUser(null);
  };

  const updateCurrentUser = (updates: Partial<User>) => {
    if (user) {
      setUser({ ...user, ...updates });
    }
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, updateCurrentUser }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};
